ALTER TYPE "UserRole" ADD VALUE IF NOT EXISTS 'ADVISOR';
ALTER TYPE "UserRole" ADD VALUE IF NOT EXISTS 'DEVELOPER';
ALTER TYPE "UserRole" ADD VALUE IF NOT EXISTS 'CLIENT';
CREATE TYPE "PortalRole" AS ENUM ('ADMIN','ADVISOR','DEVELOPER','CLIENT');
CREATE TYPE "AiConversationType" AS ENUM ('ADVISOR','CLIENT','PROPERTY_RECOMMENDATION','VISA_GUIDANCE','RETIREMENT_PLANNING');
CREATE TYPE "DocumentType" AS ENUM ('PASSPORT','VISA_DOCUMENT','PROPERTY_CONTRACT','RESERVATION_AGREEMENT','PAYMENT_RECEIPT','HEALTHCARE_DOCUMENT','INSURANCE_POLICY','TRAVEL_DOCUMENT','BROCHURE','PHOTO','VIDEO','OTHER');
CREATE TYPE "VisaWorkflowStatus" AS ENUM ('NOT_STARTED','DOCUMENT_COLLECTION','SUBMITTED','UNDER_REVIEW','APPROVED','REJECTED','RENEWAL_REQUIRED','EXPIRED');
CREATE TYPE "WorkflowEventType" AS ENUM ('NEW_LEAD','CLIENT_PROFILE_UPDATED','VISA_STATUS_UPDATED','PROPERTY_HANDOVER','DOCUMENT_EXPIRY');
CREATE TYPE "WorkflowRunStatus" AS ENUM ('PENDING','SENT','FAILED','COMPLETED');
CREATE TYPE "AppointmentType" AS ENUM ('CONSULTATION','PROPERTY_VIEWING','VISA_MEETING','HEALTHCARE_INTRODUCTION','DEVELOPER_MEETING');
CREATE TYPE "CommunicationType" AS ENUM ('EMAIL','CALL','MEETING','WHATSAPP','NOTE');
CREATE TYPE "ReportType" AS ENUM ('CLIENT_PROPERTY','RETIREMENT_SUITABILITY','INVESTMENT_ANALYSIS','PORTFOLIO','VISA_STATUS','PIPELINE','EXECUTIVE');
CREATE TYPE "ReportFormat" AS ENUM ('PDF','EXCEL');
CREATE TYPE "SubmissionStatus" AS ENUM ('DRAFT','SUBMITTED','APPROVED','REJECTED');
ALTER TABLE projects ADD COLUMN country TEXT, ADD COLUMN province TEXT, ADD COLUMN region TEXT, ADD COLUMN city TEXT;
ALTER TABLE properties ADD COLUMN country TEXT, ADD COLUMN province TEXT, ADD COLUMN region TEXT, ADD COLUMN city TEXT, ADD COLUMN submarket TEXT;
CREATE TABLE ai_prompts (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), name TEXT NOT NULL, version INT NOT NULL, model TEXT NOT NULL DEFAULT 'gpt-4o-mini', system_prompt TEXT NOT NULL, user_template TEXT, is_active BOOLEAN NOT NULL DEFAULT true, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), UNIQUE(name, version));
CREATE TABLE ai_knowledge_base (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), category TEXT NOT NULL, title TEXT NOT NULL, region TEXT, content TEXT NOT NULL, source_url TEXT, version INT NOT NULL DEFAULT 1, is_active BOOLEAN NOT NULL DEFAULT true, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE ai_conversations (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), retiree_id UUID REFERENCES retirees(id) ON DELETE CASCADE, prompt_id UUID REFERENCES ai_prompts(id), type "AiConversationType" NOT NULL, model TEXT NOT NULL, messages JSONB NOT NULL, response TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE ai_recommendations (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), retiree_id UUID NOT NULL REFERENCES retirees(id) ON DELETE CASCADE, property_id UUID NOT NULL REFERENCES properties(id) ON DELETE CASCADE, match_score INT NOT NULL, confidence_score INT NOT NULL, explanation TEXT NOT NULL, pros TEXT[] NOT NULL DEFAULT '{}', cons TEXT[] NOT NULL DEFAULT '{}', risks TEXT[] NOT NULL DEFAULT '{}', created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE client_shortlists (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), retiree_id UUID NOT NULL REFERENCES retirees(id) ON DELETE CASCADE, property_id UUID NOT NULL REFERENCES properties(id) ON DELETE CASCADE, notes TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), UNIQUE(retiree_id, property_id));
CREATE TABLE documents (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), retiree_id UUID REFERENCES retirees(id) ON DELETE CASCADE, property_id UUID REFERENCES properties(id) ON DELETE CASCADE, document_type "DocumentType" NOT NULL, file_url TEXT NOT NULL, title TEXT NOT NULL, issue_date TIMESTAMPTZ, expiry_date TIMESTAMPTZ, version INT NOT NULL DEFAULT 1, notes TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE visa_workflows (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), retiree_id UUID NOT NULL REFERENCES retirees(id) ON DELETE CASCADE, visa_type TEXT NOT NULL, status "VisaWorkflowStatus" NOT NULL DEFAULT 'NOT_STARTED', required_documents TEXT[] NOT NULL DEFAULT '{}', missing_documents TEXT[] NOT NULL DEFAULT '{}', submission_date TIMESTAMPTZ, renewal_date TIMESTAMPTZ, expiration_date TIMESTAMPTZ, advisor_notes TEXT);
CREATE TABLE workflow_automations (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), name TEXT NOT NULL, event_type "WorkflowEventType" NOT NULL, webhook_url TEXT, enabled BOOLEAN NOT NULL DEFAULT true, payload_template JSONB, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE workflow_runs (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), automation_id UUID NOT NULL REFERENCES workflow_automations(id) ON DELETE CASCADE, retiree_id UUID, payload JSONB NOT NULL, status "WorkflowRunStatus" NOT NULL DEFAULT 'PENDING', response TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE appointments (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), retiree_id UUID REFERENCES retirees(id) ON DELETE CASCADE, title TEXT NOT NULL, type "AppointmentType" NOT NULL, start_time TIMESTAMPTZ NOT NULL, end_time TIMESTAMPTZ NOT NULL, location TEXT, calendar_provider TEXT, external_calendar_id TEXT, advisor_reminder BOOLEAN NOT NULL DEFAULT true, client_reminder BOOLEAN NOT NULL DEFAULT true);
CREATE TABLE communications (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), retiree_id UUID REFERENCES retirees(id) ON DELETE CASCADE, type "CommunicationType" NOT NULL, subject TEXT, body TEXT, direction TEXT, channel_message_id TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE portfolio_holdings (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), retiree_id UUID NOT NULL REFERENCES retirees(id) ON DELETE CASCADE, property_id UUID REFERENCES properties(id), purchase_date TIMESTAMPTZ NOT NULL, purchase_price DECIMAL NOT NULL, current_value DECIMAL, rental_income DECIMAL, expenses DECIMAL DEFAULT 0, net_yield DECIMAL, capital_appreciation DECIMAL, cash_flow DECIMAL);
CREATE TABLE rental_analytics (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), property_id UUID NOT NULL REFERENCES properties(id) ON DELETE CASCADE, month TIMESTAMPTZ NOT NULL, occupancy DECIMAL, average_daily_rate DECIMAL, monthly_revenue DECIMAL, annual_revenue DECIMAL, gross_yield DECIMAL, net_yield DECIMAL, rental_management_fees DECIMAL, market_comparison JSONB, UNIQUE(property_id, month));
CREATE TABLE developer_submissions (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), developer_id UUID REFERENCES developers(id) ON DELETE SET NULL, project_name TEXT NOT NULL, region TEXT, availability JSONB, pricing JSONB, payment_plans JSONB, status "SubmissionStatus" NOT NULL DEFAULT 'DRAFT', notes TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE report_jobs (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), report_type "ReportType" NOT NULL, format "ReportFormat" NOT NULL, parameters JSONB, file_url TEXT, status TEXT NOT NULL DEFAULT 'queued', created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE audit_logs (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), actor_id UUID, actor_role "PortalRole", action TEXT NOT NULL, entity TEXT NOT NULL, entity_id UUID, metadata JSONB, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE login_history (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID, email TEXT, ip_address TEXT, user_agent TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE document_access_logs (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), document_id UUID NOT NULL REFERENCES documents(id) ON DELETE CASCADE, actor_id UUID, action TEXT NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE INDEX ai_knowledge_base_category_region_idx ON ai_knowledge_base(category, region); CREATE INDEX ai_conversations_retiree_id_type_idx ON ai_conversations(retiree_id, type); CREATE INDEX ai_recommendations_retiree_id_match_score_idx ON ai_recommendations(retiree_id, match_score); CREATE INDEX documents_retiree_id_document_type_idx ON documents(retiree_id, document_type); CREATE INDEX documents_expiry_date_idx ON documents(expiry_date); CREATE INDEX visa_workflows_retiree_id_status_idx ON visa_workflows(retiree_id, status); CREATE INDEX workflow_automations_event_type_enabled_idx ON workflow_automations(event_type, enabled); CREATE INDEX appointments_retiree_id_start_time_idx ON appointments(retiree_id, start_time); CREATE INDEX communications_retiree_id_created_at_idx ON communications(retiree_id, created_at); CREATE INDEX audit_logs_actor_id_created_at_idx ON audit_logs(actor_id, created_at);
INSERT INTO ai_prompts (name, version, model, system_prompt, user_template) VALUES ('retirement_advisor',1,'gpt-4o-mini','You are TRLA, a Thailand retirement relocation advisor. Use only supplied client, property, visa, and knowledge-base context. Flag legal, tax, or medical uncertainty for specialist review.','Client question: {{question}}'),('property_recommender',1,'gpt-4o-mini','Recommend Thailand retirement properties using budget, lifestyle, healthcare, airport, safety, expat community, and portfolio objectives. Explain pros, cons, and risks.','Retiree: {{retiree}} Properties: {{properties}}'),('visa_guidance',1,'gpt-4o-mini','Provide Thailand visa process guidance for Retirement, DTV, LTR, and Elite visas. Do not provide legal advice; provide checklists and escalation points.','Visa context: {{visa_context}}');
INSERT INTO workflow_automations (name, event_type) VALUES ('New Lead Welcome Email','NEW_LEAD'),('Client Profile Updated Recommendations','CLIENT_PROFILE_UPDATED'),('Visa Status Updated Checklist','VISA_STATUS_UPDATED'),('Property Handover Relocation Checklist','PROPERTY_HANDOVER'),('Document Expiry Reminder','DOCUMENT_EXPIRY');
